{
  "sentences": [
    {
      "text": "你現在在做什麼？",
      "pinyin": "Nǐ xiànzài zài zuò shénme?",
      "pinyin_numeric": "ni3 xian4zai4 zai4 zuo4 shen2me0",
      "translation_en": "What are you doing now?",
      "translation_ko": "지금 뭐 하고 있어요?"
    },
    {
      "text": "我正在上網，你呢？",
      "pinyin": "Wǒ zhèngzài shàngwǎng, nǐ ne?",
      "pinyin_numeric": "wo3 zheng4zai4 shang4wang3, ni3 ne0",
      "translation_en": "I am browsing the internet, and you?",
      "translation_ko": "저는 인터넷을 하고 있어요, 당신은요?"
    },
    {
      "text": "他在忙著寫功課。",
      "pinyin": "Tā zài mángzhe xiě gōngkè.",
      "pinyin_numeric": "ta1 zai4 mang2zhe0 xie3 gong1ke4",
      "translation_en": "He is busy doing homework.",
      "translation_ko": "그는 숙제를 하고 있어요."
    },
    {
      "text": "她正在滑手機，沒有在忙。",
      "pinyin": "Tā zhèngzài huá shǒujī, méiyǒu zài máng.",
      "pinyin_numeric": "ta1 zheng4zai4 hua2 shou3ji1, mei2you3 zai4 mang2",
      "translation_en": "She is scrolling on her phone, not busy.",
      "translation_ko": "그녀는 핸드폰을 보고 있어요, 바쁘지 않아요."
    },
    {
      "text": "我現在在忙，等一下再回訊息。",
      "pinyin": "Wǒ xiànzài zài máng, děng yīxià zài huí xùnxī.",
      "pinyin_numeric": "wo3 xian4zai4 zai4 mang2, deng3 yi1xia4 zai4 hui2 xun4xi1",
      "translation_en": "I am busy now, I'll reply to the message later.",
      "translation_ko": "지금 바빠서, 잠시 후에 메시지를 답장할게요."
    },
    {
      "text": "你方便嗎？還是在忙？",
      "pinyin": "Nǐ fāngbiàn ma? Háishì zài máng?",
      "pinyin_numeric": "ni3 fang1bian4 ma0? hai2shi4 zai4 mang2?",
      "translation_en": "Are you free? Or are you busy?",
      "translation_ko": "괜찮으세요? 아니면 바쁘세요?"
    },
    {
      "text": "她正在跟朋友傳訊息。",
      "pinyin": "Tā zhèngzài gēn péngyǒu chuán xùnxī.",
      "pinyin_numeric": "ta1 zheng4zai4 gen1 peng2you3 chuan2 xun4xi1",
      "translation_en": "She is sending messages to a friend.",
      "translation_ko": "그녀는 친구와 메시지를 주고받고 있어요."
    },
    {
      "text": "不好意思打擾，你現在有空嗎？",
      "pinyin": "Bù hǎoyìsi dǎrǎo, nǐ xiànzài yǒu kòng ma?",
      "pinyin_numeric": "bu4 hao3yi4si0 da3rao3, ni3 xian4zai4 you3 kong4 ma0?",
      "translation_en": "Sorry to bother you, are you free now?",
      "translation_ko": "방해해서 죄송한데, 지금 시간 괜찮으세요?"
    },
    {
      "text": "他正在開會，現在不行。",
      "pinyin": "Tā zhèngzài kāihuì, xiànzài bùxíng.",
      "pinyin_numeric": "ta1 zheng4zai4 kai1hui4, xian4zai4 bu4xing2",
      "translation_en": "He is in a meeting, not available now.",
      "translation_ko": "그는 회의 중이라 지금 안 돼요."
    },
    {
      "text": "我快到了，正在路上。",
      "pinyin": "Wǒ kuài dào le, zhèngzài lùshàng.",
      "pinyin_numeric": "wo3 kuai4 dao4 le0, zheng4zai4 lu4shang4",
      "translation_en": "I am almost there, I'm on the way.",
      "translation_ko": "거의 도착했어요, 지금 가는 중이에요."
    }
  ]
}
